  "Vignettage": aide("Ajoute un effet d’assombrissement ou de couleur sur les bords de l’étiquette.", "Adds a darkening or color effect to the label edges.", "Voegt een verdonkerings- of kleureffect toe aan de randen van het label.", "Fügt an den Etikettenrändern einen Abdunklungs- oder Farbeffekt hinzu.", "Añade un efecto de oscurecimiento o color en los bordes de la etiqueta.", "Aggiunge un effetto di scurimento o colore sui bordi dell'etichetta."),
  "Patine": aide("Vieillit toute l’étiquette avec un voile coloré, du grain, des frottements, des micro-rayures et une usure irrégulière des bords.", "Ages the whole label with a colored wash, grain, scuffs, fine scratches, and irregular edge wear.", "Veroudert het hele label met een kleurzweem, korrel, slijtage, fijne krasjes en onregelmatige randslijtage.", "Altert das gesamte Etikett mit Farbschleier, Körnung, Scheuerstellen, feinen Kratzern und unregelmäßigem Kantenverschleiß.", "Envejece toda la etiqueta con un velo de color, grano, roces, microarañazos y desgaste irregular en los bordes.", "Invecchia l’intera etichetta con una velatura colorata, grana, sfregamenti, micrograffi e usura irregolare dei bordi."),
  "Couleur": aide("Modifie la couleur de l’effet sélectionné.", "Changes the color of the selected effect.", "Wijzigt de kleur van het geselecteerde effect.", "Ändert die Farbe des ausgewählten Effekts.", "Cambia el color del efecto seleccionado.", "Modifica il colore dell'effetto selezionato."),
  "Intensité": aide("Règle la force de l’effet.", "Adjusts the effect strength.", "Regelt de sterkte van het effect.", "Regelt die Stärke des Effekts.", "Ajusta la fuerza del efecto.", "Regola la forza dell'effetto."),
  "Opacité": aide("Règle la transparence de l’effet.", "Adjusts the effect transparency.", "Regelt de transparantie van het effect.", "Regelt die Transparenz des Effekts.", "Ajusta la transparencia del efecto.", "Regola la trasparenza dell'effetto."),
  "Épaisseur de bordure": aide("Modifie l’épaisseur de la bordure extérieure de l’étiquette.", "Changes the thickness of the label's outer border.", "Wijzigt de dikte van de buitenrand van het label.", "Ändert die Stärke des äußeren Etikettenrands.", "Cambia el grosor del borde exterior de la etiqueta.", "Modifica lo spessore del bordo esterno dell'etichetta."),
  "Bordure visible": aide("Choisissez les côtés de la bordure à afficher.", "Choose which border sides to display.", "Kies welke zijden van de rand zichtbaar zijn.", "Wählen Sie, welche Randseiten angezeigt werden.", "Elige qué lados del borde se muestran.", "Scegli quali lati del bordo mostrare."),
  "Haut / bas": aide("Affiche ou masque les traits supérieur et inférieur.", "Shows or hides the top and bottom lines.", "Toont of verbergt de boven- en onderlijnen.", "Blendet obere und untere Linien ein oder aus.", "Muestra u oculta las líneas superior e inferior.", "Mostra o nasconde le linee superiore e inferiore."),
  "Gauche / droite": aide("Affiche ou masque les traits gauche et droit.", "Shows or hides the left and right lines.", "Toont of verbergt de linker- en rechterlijnen.", "Blendet linke und rechte Linien ein oder aus.", "Muestra u oculta las líneas izquierda y derecha.", "Mostra o nasconde le linee sinistra e destra."),
  "Arrondi intérieur": aide("Arrondit seulement les coins intérieurs du ruban. La bordure extérieure reste droite.", "Rounds only the inner ribbon corners. The outer border stays square.", "Rondt alleen de binnenhoeken van het lint af. De buitenrand blijft recht.", "Rundet nur die inneren Bandecken ab. Der Außenrand bleibt gerade.", "Redondea solo las esquinas interiores de la cinta. El borde exterior queda recto.", "Arrotonda solo gli angoli interni del nastro. Il bordo esterno resta dritto."),
  "Largeur du ruban": aide("Modifie la largeur du ruban central.", "Changes the width of the central ribbon.", "Wijzigt de breedte van het centrale lint.", "Ändert die Breite des mittleren Bands.", "Cambia la anchura de la cinta central.", "Modifica la larghezza del nastro centrale."),
  "Hauteur du ruban": aide("Modifie la hauteur du ruban central.", "Changes the height of the central ribbon.", "Wijzigt de hoogte van het centrale lint.", "Ändert die Höhe des mittleren Bands.", "Cambia la altura de la cinta central.", "Modifica l'altezza del nastro centrale."),
  "Bande centrale": aide("Ajuste l’espace de séparation entre la face A et la face B.", "Adjusts the separation space between side A and side B.", "Past de scheidingsruimte tussen kant A en kant B aan.", "Passt den Abstand zwischen Seite A und Seite B an.", "Ajusta el espacio de separación entre la cara A y la cara B.", "Regola lo spazio di separazione tra lato A e lato B."),
  "Taille bande gauche": aide("Largeur du décor gauche.", "Left decoration width.", "Breedte van decor links.", "Breite des linken Dekors.", "Anchura del decorado izquierdo.", "Larghezza decoro sinistro."),
  "Orientation gauche": aide("Inclina le décor gauche.", "Tilts left decoration.", "Kantelt decor links.", "Neigt das linke Dekor.", "Inclina el decorado izquierdo.", "Inclina il decoro sinistro."),
  "Taille bande droite": aide("Largeur du décor droit.", "Right decoration width.", "Breedte van decor rechts.", "Breite des rechten Dekors.", "Anchura del decorado derecho.", "Larghezza decoro destro."),
